/* ============================================================================
 * pm-b3-tracer.js
 *
 * Sprint 6 task 5 — Walk-to-b3 widget controller.
 *
 * Loads:
 *   - AutoGenerated/dependency_chains.json      (Arithma symbolic chains)
 *   - AutoGenerated/eml_dependency_chains.json  (EML op-token chains)
 *
 * Renders a two-column modal SVG dependency graph for any formula id and
 * exposes:
 *   - window.PMTraceToB3(formulaId)            — programmatic entry point
 *   - delegated click handler for [data-action="trace-b3"] elements
 *   - back-compat hook for [data-pm-trace] buttons added by
 *     pm-formula-renderer.js in Sprint 3 #6.
 *
 * Plain JS, no graph library. Top-down layout: root formula at the top,
 * each path step descending vertically, b3_leaf (or the deepest visited
 * node) at the bottom.
 *
 * Copyright (c) 2025 Andrew Keith Watts.
 * ============================================================================ */
(function () {
    'use strict';

    // ── Configuration ──────────────────────────────────────────────────────
    const CANDIDATE_PATHS = [
        '../AutoGenerated/',  // when served from /Pages/...
        './AutoGenerated/',   // when served from /
        '/AutoGenerated/',    // absolute
        'AutoGenerated/'      // relative bare
    ];

    const ARITHMA_FILE = 'dependency_chains.json';
    const EML_FILE = 'eml_dependency_chains.json';

    const NODE_W = 180;
    const NODE_H = 44;
    const V_GAP = 60;       // vertical gap between node centres
    const PADDING = 24;
    const SVG_NS = 'http://www.w3.org/2000/svg';

    // ── State ──────────────────────────────────────────────────────────────
    let arithmaChainsP = null;  // Promise<{chains, ...}>
    let emlChainsP = null;
    let modalEl = null;

    // ── Data loading ───────────────────────────────────────────────────────
    async function fetchFirst(filename) {
        let lastErr = null;
        for (const prefix of CANDIDATE_PATHS) {
            try {
                const resp = await fetch(prefix + filename, { cache: 'no-store' });
                if (resp.ok) return await resp.json();
                lastErr = new Error('HTTP ' + resp.status + ' for ' + prefix + filename);
            } catch (e) {
                lastErr = e;
            }
        }
        throw lastErr || new Error('Could not load ' + filename);
    }

    function loadArithma() {
        if (!arithmaChainsP) arithmaChainsP = fetchFirst(ARITHMA_FILE);
        return arithmaChainsP;
    }

    function loadEml() {
        if (!emlChainsP) emlChainsP = fetchFirst(EML_FILE);
        return emlChainsP;
    }

    // ── DOM helpers ────────────────────────────────────────────────────────
    function svg(tag, attrs) {
        const el = document.createElementNS(SVG_NS, tag);
        if (attrs) {
            for (const k in attrs) el.setAttribute(k, attrs[k]);
        }
        return el;
    }

    function escapeText(s) {
        if (s == null) return '';
        return String(s).replace(/[<>&"]/g, ch => ({
            '<': '&lt;', '>': '&gt;', '&': '&amp;', '"': '&quot;'
        })[ch]);
    }

    // ── Modal scaffolding ──────────────────────────────────────────────────
    function ensureModal() {
        if (modalEl) return modalEl;

        modalEl = document.createElement('div');
        modalEl.className = 'pm-b3-modal';
        modalEl.setAttribute('role', 'dialog');
        modalEl.setAttribute('aria-modal', 'true');
        modalEl.setAttribute('aria-labelledby', 'pm-b3-modal-title');

        modalEl.innerHTML = [
            '<div class="pm-b3-modal__overlay" data-pm-b3-close="1"></div>',
            '<div class="pm-b3-modal__panel">',
                '<div class="pm-b3-modal__header">',
                    '<div>',
                        '<h2 class="pm-b3-modal__title" id="pm-b3-modal-title">Trace to b<sub>3</sub></h2>',
                        '<p class="pm-b3-modal__subtitle" data-pm-b3-subtitle></p>',
                    '</div>',
                    '<button type="button" class="pm-b3-modal__close" aria-label="Close" data-pm-b3-close="1">&times;</button>',
                '</div>',
                '<div class="pm-b3-modal__body">',
                    '<div class="pm-b3-cols">',
                        '<div class="pm-b3-col" data-pm-b3-col="arithma">',
                            '<div class="pm-b3-col__head">',
                                '<h3 class="pm-b3-col__title">Arithma (symbolic)</h3>',
                                '<span class="pm-b3-col__meta" data-pm-b3-meta="arithma"></span>',
                            '</div>',
                            '<svg class="pm-b3-col__svg" data-pm-b3-svg="arithma" preserveAspectRatio="xMidYMin meet"></svg>',
                        '</div>',
                        '<div class="pm-b3-col" data-pm-b3-col="eml">',
                            '<div class="pm-b3-col__head">',
                                '<h3 class="pm-b3-col__title">EML (op-token)</h3>',
                                '<span class="pm-b3-col__meta" data-pm-b3-meta="eml"></span>',
                            '</div>',
                            '<svg class="pm-b3-col__svg" data-pm-b3-svg="eml" preserveAspectRatio="xMidYMin meet"></svg>',
                        '</div>',
                    '</div>',
                '</div>',
                '<div class="pm-b3-modal__footer" data-pm-b3-footer></div>',
            '</div>'
        ].join('');

        document.body.appendChild(modalEl);

        // Close handlers
        modalEl.addEventListener('click', (e) => {
            const t = e.target;
            if (t && t.getAttribute && t.getAttribute('data-pm-b3-close') === '1') {
                closeModal();
            }
        });
        document.addEventListener('keydown', (e) => {
            if (e.key === 'Escape' && modalEl && modalEl.classList.contains('is-open')) {
                closeModal();
            }
        });

        return modalEl;
    }

    function openModal() {
        const m = ensureModal();
        m.classList.add('is-open');
        document.body.style.overflow = 'hidden';
    }

    function closeModal() {
        if (!modalEl) return;
        modalEl.classList.remove('is-open');
        document.body.style.overflow = '';
    }

    // ── Arrow marker (shared, injected once into <defs>) ───────────────────
    function ensureArrowDef(svgEl) {
        if (svgEl.querySelector('defs#pm-b3-defs')) return;
        const defs = svg('defs', { id: 'pm-b3-defs' });
        const marker = svg('marker', {
            id: 'pm-b3-arrow',
            viewBox: '0 0 10 10',
            refX: '9', refY: '5',
            markerWidth: '7', markerHeight: '7',
            orient: 'auto-start-reverse'
        });
        const path = svg('path', { d: 'M 0 0 L 10 5 L 0 10 z', fill: '#888' });
        marker.appendChild(path);
        defs.appendChild(marker);
        svgEl.appendChild(defs);
    }

    // ── Node rendering ─────────────────────────────────────────────────────
    function drawNode(svgEl, x, y, label, sub, kind) {
        // kind: 'root' | 'b3' | 'op' | 'mid'
        const g = svg('g', {
            class: 'pm-b3-node' + (kind ? ' pm-b3-node--' + kind : ''),
            transform: `translate(${x - NODE_W / 2}, ${y - NODE_H / 2})`
        });
        const rect = svg('rect', { width: NODE_W, height: NODE_H });
        g.appendChild(rect);

        const t1 = svg('text', {
            x: NODE_W / 2,
            y: sub ? NODE_H / 2 - 6 : NODE_H / 2,
            class: 'pm-b3-label'
        });
        t1.textContent = label;
        g.appendChild(t1);

        if (sub) {
            const t2 = svg('text', { x: NODE_W / 2, y: NODE_H / 2 + 10, class: 'pm-b3-sub' });
            t2.textContent = sub;
            g.appendChild(t2);
        }

        svgEl.appendChild(g);
        return g;
    }

    function drawEdge(svgEl, x1, y1, x2, y2, viaLabel) {
        const path = svg('path', {
            class: 'pm-b3-edge',
            d: `M ${x1} ${y1 + NODE_H / 2} L ${x2} ${y2 - NODE_H / 2}`
        });
        svgEl.appendChild(path);

        if (viaLabel) {
            const gv = svg('g', { class: 'pm-b3-edge--via' });
            const tx = (x1 + x2) / 2 + 8;
            const ty = (y1 + y2) / 2 + 3;
            const t = svg('text', { x: tx, y: ty });
            t.textContent = viaLabel;
            gv.appendChild(t);
            svgEl.appendChild(gv);
        }
    }

    // ── Arithma chain rendering ────────────────────────────────────────────
    /**
     * Render a single top-down chain.
     *
     * @param {SVGSVGElement} svgEl
     * @param {Array<{label:string, sub?:string, kind:string}>} nodes
     * @param {Array<string|null>} edgeLabels  length = nodes.length - 1
     */
    function renderChain(svgEl, nodes, edgeLabels) {
        // Reset
        while (svgEl.firstChild) svgEl.removeChild(svgEl.firstChild);
        ensureArrowDef(svgEl);

        const n = nodes.length;
        const height = PADDING * 2 + n * NODE_H + (n - 1) * (V_GAP - NODE_H);
        const width = NODE_W + PADDING * 2;
        svgEl.setAttribute('viewBox', `0 0 ${width} ${height}`);
        svgEl.setAttribute('width', '100%');
        svgEl.style.minHeight = Math.min(420, height) + 'px';

        const cx = width / 2;
        const positions = [];
        for (let i = 0; i < n; i++) {
            const y = PADDING + NODE_H / 2 + i * V_GAP;
            positions.push({ x: cx, y });
        }

        // Edges (draw first so nodes overlay them)
        for (let i = 0; i < n - 1; i++) {
            const p = positions[i];
            const q = positions[i + 1];
            drawEdge(svgEl, p.x, p.y, q.x, q.y, edgeLabels[i] || null);
        }

        // Nodes
        for (let i = 0; i < n; i++) {
            const { x, y } = positions[i];
            const node = nodes[i];
            drawNode(svgEl, x, y, node.label, node.sub, node.kind);
        }
    }

    function renderArithmaColumn(chain, formulaId, metaEl, svgEl) {
        if (!chain) {
            svgEl.outerHTML = '<div class="pm-b3-col__empty">No Arithma chain on record for <code>'
                + escapeText(formulaId) + '</code>.</div>';
            metaEl.textContent = '';
            return;
        }
        const path = chain.path || [];
        const via = chain.via || [];
        const rooted = !!chain.b3_rooted;

        const nodes = path.map((step, i) => {
            if (step === 'b3_leaf') {
                return {
                    label: 'b₃ = 24',
                    sub: 'Third Betti number (G₂ manifold)',
                    kind: 'b3'
                };
            }
            return {
                label: step,
                sub: i === 0 ? 'formula' : 'intermediate',
                kind: i === 0 ? 'root' : 'mid'
            };
        });

        // If the chain doesn't terminate at b3_leaf, append a synthetic
        // "(not yet b3-rooted)" marker so the user understands why no
        // b3 node appears.
        if (path.length > 0 && path[path.length - 1] !== 'b3_leaf') {
            nodes.push({
                label: 'b₃ = 24',
                sub: rooted ? 'terminus' : '(chain does not yet reach b₃)',
                kind: rooted ? 'b3' : 'op'
            });
            via.push(null);
        }

        // edge labels: via[i] connects nodes[i] -> nodes[i+1]
        const edgeLabels = [];
        for (let i = 0; i < nodes.length - 1; i++) {
            edgeLabels.push(via[i] || null);
        }

        renderChain(svgEl, nodes, edgeLabels);

        const compRatio = chain.compression_ratio != null
            ? '×' + Number(chain.compression_ratio).toFixed(2)
            : '';
        metaEl.textContent =
            `depth ${chain.depth ?? path.length} · `
            + (rooted ? 'b₃-rooted' : 'not yet b₃-rooted')
            + (compRatio ? ` · compress ${compRatio}` : '');
    }

    // ── EML chain rendering ────────────────────────────────────────────────
    function renderEmlColumn(chain, formulaId, metaEl, svgEl) {
        if (!chain) {
            svgEl.outerHTML = '<div class="pm-b3-col__empty">No EML chain on record for <code>'
                + escapeText(formulaId) + '</code>.</div>';
            metaEl.textContent = '';
            return;
        }
        const paths = chain.paths || [];
        const rooted = !!chain.b3_rooted;

        if (!paths.length) {
            // Empty SVG, fall back to a small note
            while (svgEl.firstChild) svgEl.removeChild(svgEl.firstChild);
            svgEl.setAttribute('viewBox', '0 0 200 120');
            const t = svg('text', {
                x: 100, y: 60,
                fill: '#888',
                'text-anchor': 'middle',
                'font-family': 'Source Code Pro, monospace',
                'font-size': '12'
            });
            t.textContent = rooted ? 'EML chain has no op-token steps' : 'EML chain not b₃-rooted';
            svgEl.appendChild(t);
            metaEl.textContent = `depth ${chain.depth ?? 0} · leaves ${chain.leaves ?? 0}`;
            return;
        }

        // Show the first (canonical) op-token path.
        const opTokens = paths[0];
        // Build nodes: root = formula, then one node per op-token, terminating
        // at b3_leaf if the last token is '24' (raw-24) or b3_leaf.
        const nodes = [{
            label: formulaId,
            sub: 'formula',
            kind: 'root'
        }];
        for (let i = 0; i < opTokens.length; i++) {
            const tok = opTokens[i];
            if (tok === '24') {
                nodes.push({
                    label: 'b₃ = 24',
                    sub: 'raw-24 leaf',
                    kind: 'b3'
                });
            } else if (tok === 'b3_leaf') {
                nodes.push({
                    label: 'b₃ = 24',
                    sub: 'b3_leaf',
                    kind: 'b3'
                });
            } else {
                nodes.push({
                    label: tok,
                    sub: 'op',
                    kind: 'op'
                });
            }
        }

        // No 'via' labels available for EML chains.
        const edgeLabels = new Array(nodes.length - 1).fill(null);
        renderChain(svgEl, nodes, edgeLabels);

        const altCount = paths.length > 1 ? ` · ${paths.length} paths` : '';
        metaEl.textContent =
            `depth ${chain.depth ?? 0} · leaves ${chain.leaves ?? 0} · `
            + (rooted ? 'b₃-rooted' : 'not yet b₃-rooted')
            + altCount;
    }

    // ── Main entry point ───────────────────────────────────────────────────
    async function showTrace(formulaId) {
        const m = ensureModal();
        const titleEl = m.querySelector('[data-pm-b3-subtitle]');
        const aMeta = m.querySelector('[data-pm-b3-meta="arithma"]');
        const eMeta = m.querySelector('[data-pm-b3-meta="eml"]');
        const aSvg = m.querySelector('[data-pm-b3-svg="arithma"]');
        const eSvg = m.querySelector('[data-pm-b3-svg="eml"]');
        const footer = m.querySelector('[data-pm-b3-footer]');

        titleEl.textContent = formulaId + ' → b₃';
        aMeta.textContent = 'loading…';
        eMeta.textContent = 'loading…';
        // Clear svgs to placeholder
        [aSvg, eSvg].forEach(s => { while (s.firstChild) s.removeChild(s.firstChild); });

        openModal();

        let arithmaDoc, emlDoc;
        try {
            [arithmaDoc, emlDoc] = await Promise.all([loadArithma(), loadEml()]);
        } catch (err) {
            footer.textContent = 'Failed to load dependency chain data: ' + (err && err.message);
            aMeta.textContent = '';
            eMeta.textContent = '';
            return;
        }

        const aChains = (arithmaDoc && arithmaDoc.chains) || {};
        const eChains = (emlDoc && emlDoc.chains) || {};
        const aChain = aChains[formulaId];
        const eChain = eChains[formulaId];

        renderArithmaColumn(aChain, formulaId, aMeta, aSvg);
        renderEmlColumn(eChain, formulaId, eMeta, eSvg);

        // Footer compression message
        const aDepth = aChain && aChain.depth ? aChain.depth : 0;
        const eDepth = eChain && eChain.depth ? eChain.depth : 0;
        const intermediates = Math.max(0, (aChain && aChain.path ? aChain.path.length : 0) - 2);
        const ratio = aChain && aChain.compression_ratio ? aChain.compression_ratio : null;
        footer.innerHTML =
            `Compression: <strong>${intermediates}</strong> intermediate formula(s) collapse to a single value `
            + `derived from one seed (b<sub>3</sub> = 24). `
            + `Arithma depth = ${aDepth}, EML depth = ${eDepth}`
            + (ratio ? ` · ratio ×${Number(ratio).toFixed(2)}` : '')
            + `. Both registries independently agree on the b<sub>3</sub> root for this formula.`;
    }

    // ── Public API & event wiring ─────────────────────────────────────────
    window.PMTraceToB3 = function (formulaId) {
        if (!formulaId) return;
        showTrace(String(formulaId)).catch(err => {
            console.error('[pm-b3-tracer] showTrace failed:', err);
        });
    };

    // Delegated click handler — listens for data-action="trace-b3" and the
    // back-compat data-pm-trace attribute from pm-formula-renderer.js.
    document.addEventListener('click', (e) => {
        let el = e.target;
        while (el && el !== document.body) {
            if (el.getAttribute) {
                const action = el.getAttribute('data-action');
                const traceId = el.getAttribute('data-pm-trace');
                const explicit = el.getAttribute('data-pm-b3-trace');
                if (action === 'trace-b3' || traceId || explicit) {
                    const id = explicit
                        || el.getAttribute('data-formula-id')
                        || traceId
                        || el.dataset && el.dataset.formula;
                    if (id) {
                        e.preventDefault();
                        window.PMTraceToB3(id);
                        return;
                    }
                }
            }
            el = el.parentNode;
        }
    });

    // Optional: preload chain data shortly after page idle so the first
    // click is instant. Wrapped in a try/catch — failure here is non-fatal.
    if ('requestIdleCallback' in window) {
        window.requestIdleCallback(() => {
            loadArithma().catch(() => {});
            loadEml().catch(() => {});
        }, { timeout: 4000 });
    }

    console.log('[PM] b3 tracer initialised');
})();
